import * as THREE from 'three';
export class FeaturePointsGeometry extends THREE.BufferGeometry {
    update(tracksData) {
        const points = tracksData.length / 2;
        const coords = points * 3;
        const arr = new Float32Array(coords);
        // eslint-disable-next-line no-plusplus
        for (let i = 0; i < points; i++) {
            arr[i * 3 + 0] = tracksData[i * 2 + 0];
            arr[i * 3 + 1] = tracksData[i * 2 + 1];
            arr[i * 3 + 2] = 0;
        }
        this.setAttribute('position', new THREE.BufferAttribute(arr, 3));
    }
}
